SELECT

FROM order_info oi
LEFT JOIN user u1 ON oi.buyer_id = u1.id
LEFT JOIN user u2 ON oi.seller_id = u2.id



        AND oi.order_no LIKE CONCAT('%', #{orderNo}, '%')



        AND oi.buyer_id = #{buyerId}



        AND oi.seller_id = #{sellerId}



        AND oi.goods_id = #{goodsId}



        AND oi.order_status = #{orderStatus}



        AND oi.refund_status = #{refundStatus}



        AND oi.create_time >= #{startTime}



        AND oi.create_time <= #{endTime}


ORDER BY oi.create_time DESC
